Complete this code for a timeline animation controller with play/pause/seek:

```typescript
class TimelineController {
    private _timeline: ccs.ActionTimeline;
    private _node: cc.Node;
    // TODO: implement load, play, pause, seek, getProgress
}
```

output:
```typescript
class TimelineController {
    private _timeline: ccs.ActionTimeline;
    private _node: cc.Node;
    private _isPlaying: boolean = false;

    constructor(node: cc.Node) {
        this._node = node;
    }

    load(csbFile: string): void {
        this._timeline = ccs.actionManager.loadAnimationActionWithFile(csbFile);
        this._node.runAction(this._timeline);
        this._timeline.gotoFrameAndPause(0);
        this._isPlaying = false;
    }

    play(loop: boolean = false): void {
        if (!this._timeline) return;
        const frame = this._timeline.getCurrentFrame();
        this._timeline.gotoFrameAndPlay(frame, loop);
        this._isPlaying = true;
    }

    playFromStart(loop: boolean = false): void {
        if (!this._timeline) return;
        this._timeline.gotoFrameAndPlay(0, loop);
        this._isPlaying = true;
    }

    pause(): void {
        if (!this._timeline) return;
        const frame = this._timeline.getCurrentFrame();
        this._timeline.gotoFrameAndPause(frame);
        this._isPlaying = false;
    }

    seek(frame: number): void {
        if (!this._timeline) return;
        this._timeline.setCurrentFrame(frame);
        if (!this._isPlaying) {
            this._timeline.gotoFrameAndPause(frame);
        }
    }

    getProgress(): number {
        if (!this._timeline) return 0;
        const start = this._timeline.getStartFrame();
        const end = this._timeline.getEndFrame();
        const cur = this._timeline.getCurrentFrame();
        const range = end - start;
        if (range <= 0) return 0;
        return (cur - start) / range;
    }

    setSpeed(speed: number): void {
        if (!this._timeline) return;
        this._timeline.setTimeSpeed(speed);
    }

    isPlaying(): boolean {
        return this._isPlaying;
    }
}

// Usage:
const ctrl = new TimelineController(dialogNode);
ctrl.load('res/ui/dialog_anim.csb');
ctrl.playFromStart(false);
ctrl.setSpeed(1.5);
```

instruction:
Find and fix the bug in this animation event handler:

```typescript
armature.animation.setMovementEventCallFunc((arm, movType, movId) => {
    if (movType === 'COMPLETE') {
        arm.animation.play('idle', 5, -1);
    }
});
```

output:
The bug is comparing `movType` to the string `'COMPLETE'` instead of the enum constant `ccs.MovementEventType.COMPLETE`. The `movType` parameter is a number, not a string.

Fixed code:
```typescript
armature.animation.setMovementEventCallFunc((arm, movType, movId) => {
    if (movType === ccs.MovementEventType.COMPLETE) {
        arm.animation.play('idle', 5, -1);
    }
});
```

The available constants are:
- `ccs.MovementEventType.START` — animation started
- `ccs.MovementEventType.COMPLETE` — animation finished (non-looping)
- `ccs.MovementEventType.LOOP_COMPLETE` — one loop iteration completed

Detect orientation and adjust layout using director methods:

```typescript
class AdaptiveScene extends cc.Scene {
    private _isLandscape: boolean;

    onEnter(): void {
        super.onEnter();
        this.detectOrientation();
        this.layoutForOrientation();
        this.scheduleUpdate();
    }

    private detectOrientation(): void {
        const winSize = cc.director.getWinSize();
        this._isLandscape = winSize.width > winSize.height;
    }

    private layoutForOrientation(): void {
        const winSize = cc.director.getWinSize();
        const cx = winSize.width / 2;
        const cy = winSize.height / 2;

        if (this._isLandscape) {
            this.layoutLandscape(winSize, cx, cy);
        } else {
            this.layoutPortrait(winSize, cx, cy);
        }
    }

    private layoutLandscape(size: cc.Size, cx: number, cy: number): void {
        // Side-by-side layout
        cc.log('Landscape:', size.width, 'x', size.height);
    }

    private layoutPortrait(size: cc.Size, cx: number, cy: number): void {
        // Stacked layout
        cc.log('Portrait:', size.width, 'x', size.height);
    }

    update(dt: number): void {
        // Check for orientation change
        const winSize = cc.director.getWinSize();
        const nowLandscape = winSize.width > winSize.height;
        if (nowLandscape !== this._isLandscape) {
            this._isLandscape = nowLandscape;
            this.layoutForOrientation();
        }
    }
}
```

Use `cc.director.getWinSize()` each frame to detect orientation changes, then re-layout the UI accordingly.

```typescript
class SteeringAgent extends cc.Node {
    private _velocity: cc.Point = cc.p(0, 0);
    private _maxSpeed: number;
    private _maxForce: number;
    private _arriveRadius: number;
    private _target: cc.Point;
    private _sprite: cc.Sprite;

    constructor(spritePath: string, maxSpeed: number, maxForce: number, arriveRadius: number) {
        super();
        this._maxSpeed = maxSpeed;
        this._maxForce = maxForce;
        this._arriveRadius = arriveRadius;
        this._target = cc.p(0, 0);

        this._sprite = new cc.Sprite(spritePath);
        this.addChild(this._sprite);
        this.scheduleUpdate();
    }

    setTarget(target: cc.Point): void {
        this._target = target;
    }

    update(dt: number): void {
        const pos = this.getPosition();
        const desired = cc.pSub(this._target, pos);
        const dist = cc.pLength(desired);

        if (dist < 1) return; // close enough

        let speed: number;
        if (dist < this._arriveRadius) {
            // Arrive: slow down as we approach
            speed = this._maxSpeed * (dist / this._arriveRadius);
        } else {
            speed = this._maxSpeed;
        }

        const desiredVel = cc.pMult(cc.pNormalize(desired), speed);

        // Steering force
        let steer = cc.pSub(desiredVel, this._velocity);
        const steerLen = cc.pLength(steer);
        if (steerLen > this._maxForce) {
            steer = cc.pMult(cc.pNormalize(steer), this._maxForce);
        }

        // Apply force
        this._velocity = cc.pAdd(this._velocity, cc.pMult(steer, dt));
        const velLen = cc.pLength(this._velocity);
        if (velLen > this._maxSpeed) {
            this._velocity = cc.pMult(cc.pNormalize(this._velocity), this._maxSpeed);
        }

        // Move
        this.setPosition(cc.pAdd(pos, cc.pMult(this._velocity, dt)));

        // Rotate to face movement direction
        if (velLen > 1) {
            const angle = Math.atan2(this._velocity.y, this._velocity.x) * cc.DEG;
            this._sprite.setRotation(-angle);
        }
    }
}

// Usage:
const agent = new SteeringAgent('res/arrow.png', 200, 400, 80);
agent.setPosition(cc.p(50, 50));
agent.setTarget(cc.p(400, 280));
this.addChild(agent);
```

`cc.sys.dump()` outputs system information to the console for debugging:

```typescript
cc.sys.dump(): void  // JSB only
```

Call it during development to inspect the runtime environment:

```typescript
// Debug helper — call on game start
function logSystemInfo(): void {
    cc.log('=== System Info ===');
    cc.log('Platform:', cc.sys.platform);
    cc.log('OS:', cc.sys.os);
    cc.log('Is Native:', cc.sys.isNative);
    cc.log('Is Mobile:', cc.sys.isMobile);
    cc.log('Language:', cc.sys.language);

    if (!cc.sys.isNative) {
        cc.log('Browser:', cc.sys.browserType, cc.sys.browserVersion);
        cc.log('Window:', cc.sys.windowPixelResolution.width, 'x', cc.sys.windowPixelResolution.height);
    }

    cc.log('Capabilities:');
    cc.log('  OpenGL:', cc.sys.capabilities.opengl);
    cc.log('  Touch:', cc.sys.capabilities.touches);
    cc.log('  Keyboard:', cc.sys.capabilities.keyboard);
    cc.log('  Mouse:', cc.sys.capabilities.mouse);
    cc.log('  Accelerometer:', cc.sys.capabilities.accelerometer);

    // JSB dump for native platforms
    if (cc.sys.isNative) {
        cc.sys.dump();
    }
}
```

`cc.sys.dump()` is a JSB-only method that prints internal engine state. Use the manual logging approach above for cross-platform debugging.

