instruction:
Find the bug in this custom event code:

```typescript
class ScoreManager {
    private listener: cc.EventListener;

    init(): void {
        this.listener = cc.eventManager.addCustomListener('score:add', (event) => {
            const data = event.getUserData();
            this.addScore(data.points);
        });
    }

    addScore(points: number): void {
        cc.log('Added', points, 'points');
    }

    notifyScoreAdded(points: number): void {
        cc.eventManager.dispatchCustomEvent('score_add', { points: points });
    }
}
```

output:
There are two bugs:

**Bug 1: Event name mismatch.** The listener subscribes to `'score:add'` but `notifyScoreAdded` dispatches `'score_add'` (underscore instead of colon). The event will never be received.

**Bug 2: Missing type parameter on `getUserData`.** Without it, the return is untyped and will lack type safety.

Fixed code:
```typescript
class ScoreManager {
    private listener: cc.EventListener;
    private static readonly SCORE_EVENT = 'score:add';

    init(): void {
        this.listener = cc.eventManager.addCustomListener(
            ScoreManager.SCORE_EVENT,
            (event: cc.Event) => {
                const data = event.getUserData<{ points: number }>();
                this.addScore(data.points);
            }
        );
    }

    addScore(points: number): void {
        cc.log('Added', points, 'points');
    }

    notifyScoreAdded(points: number): void {
        cc.eventManager.dispatchCustomEvent(
            ScoreManager.SCORE_EVENT, // FIX: use same constant
            { points: points }
        );
    }

    destroy(): void {
        cc.eventManager.removeListener(this.listener);
    }
}
```

Extracting the event name into a constant prevents name mismatch bugs.

```typescript
class NotificationBanner {
    private banner: cc.LayerColor;
    private label: cc.LabelTTF;
    private bannerHeight: number = 50;

    constructor() {
        const winSize = cc.director.getWinSize();
        this.banner = new cc.LayerColor(
            cc.color(40, 40, 40, 220), winSize.width, this.bannerHeight
        );
        this.banner.setPosition(0, winSize.height);

        this.label = new cc.LabelTTF('', 'Arial', 18);
        this.label.setPosition(winSize.width / 2, this.bannerHeight / 2);
        this.banner.addChild(this.label);
    }

    getNode(): cc.LayerColor { return this.banner; }

    show(parent: cc.Node, message: string, duration: number = 3.0): void {
        const winSize = cc.director.getWinSize();
        const showY = winSize.height - this.bannerHeight;
        this.label.setString(message);
        if (!this.banner.getParent()) parent.addChild(this.banner, 999);
        this.banner.setPositionY(winSize.height);
        this.banner.runAction(cc.sequence(
            cc.moveTo(0.3, cc.p(0, showY)),
            cc.delayTime(duration),
            cc.moveTo(0.3, cc.p(0, winSize.height))
        ));
    }
}

const notif = new NotificationBanner();
notif.show(this, 'Achievement Unlocked!', 2.0);
```

The banner is a `cc.LayerColor` positioned above the screen. `show()` animates it down, holds, then slides back up.

