```typescript
class CoordinateHelper {
    static screenToWorld(screenPoint: cc.Point): cc.Point {
        // In Cocos2d-x JS, screen coords = world coords for default camera
        return cc.p(screenPoint.x, screenPoint.y);
    }

    static worldToNode(worldPoint: cc.Point, node: cc.Node): cc.Point {
        return node.convertToNodeSpace(worldPoint);
    }

    static nodeToWorld(localPoint: cc.Point, node: cc.Node): cc.Point {
        return node.convertToWorldSpace(localPoint);
    }

    static nodeToNode(
        point: cc.Point,
        fromNode: cc.Node,
        toNode: cc.Node
    ): cc.Point {
        const worldPoint = fromNode.convertToWorldSpace(point);
        return toNode.convertToNodeSpace(worldPoint);
    }

    static getWorldCenter(node: cc.Node): cc.Point {
        const size = node.getContentSize();
        const localCenter = cc.p(size.width / 2, size.height / 2);
        return node.convertToWorldSpace(localCenter);
    }

    static isWorldPointInNode(
        worldPoint: cc.Point,
        node: cc.Node
    ): boolean {
        const localPoint = node.convertToNodeSpace(worldPoint);
        const size = node.getContentSize();
        const localRect = cc.rect(0, 0, size.width, size.height);
        return cc.rectContainsPoint(localRect, localPoint);
    }

    // Manual transform using AffineTransform
    static applyNodeTransform(
        localPoint: cc.Point,
        node: cc.Node
    ): cc.Point {
        const transform: cc.AffineTransform = node.getNodeToWorldTransform();
        return cc.pointApplyAffineTransform(localPoint, transform);
    }
}

// Usage:
const worldPos = CoordinateHelper.nodeToWorld(cc.p(0, 0), childNode);
const localPos = CoordinateHelper.worldToNode(touchPos, parentNode);
const hit = CoordinateHelper.isWorldPointInNode(touchPos, button);
```

instruction:
Review this touch handling code and identify potential problems:

```typescript
class Slider extends cc.Sprite {
    onEnter(): void {
        super.onEnter();
        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: function(touch, event) {
                this.startDrag(touch.getLocation());
                return true;
            },
            onTouchMoved: function(touch, event) {
                this.updateDrag(touch.getLocation());
            }
        }, this);
    }
}
```

output:
Issues found:

1. **`this` context is wrong.** Using `function()` instead of arrow functions means `this` inside the callbacks does NOT refer to the `Slider` instance — it refers to the listener object or `undefined` in strict mode. Calling `this.startDrag()` and `this.updateDrag()` will crash.

2. **No listener cleanup.** No `onExit` to remove the listener.

3. **Missing `swallowTouches`.** Touches will propagate to nodes behind the slider.

Fixed code:
```typescript
class Slider extends cc.Sprite {
    private _listener: cc.EventListener;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            swallowTouches: true,
            onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
                // Arrow function preserves `this` as the Slider instance
                this.startDrag(touch.getLocation());
                return true;
            },
            onTouchMoved: (touch: cc.Touch, event: cc.EventTouch): void => {
                this.updateDrag(touch.getLocation());
            }
        }, this);
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

Always use arrow functions (`=>`) in event listener callbacks when you need to access the enclosing class instance.

Use mouse move deltas for first-person or orbit camera rotation:

```typescript
class MouseLookCamera extends cc.Layer {
    private _listener: cc.EventListener;
    private _rotationX: number = 0;
    private _rotationY: number = 0;
    private _isLocked: boolean = false;
    private static readonly SENSITIVITY = 0.3;

    onEnter(): void {
        super.onEnter();
        this._listener = cc.eventManager.addListener({
            event: cc.EventListener.MOUSE,
            onMouseDown: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = true;
                }
            },
            onMouseUp: (event: cc.EventMouse): void => {
                if (event.getButton() === cc.EventMouse.BUTTON_RIGHT) {
                    this._isLocked = false;
                }
            },
            onMouseMove: (event: cc.EventMouse): void => {
                if (!this._isLocked) return;
                const dx: number = event.getDeltaX();
                const dy: number = event.getDeltaY();
                this._rotationY += dx * MouseLookCamera.SENSITIVITY;
                this._rotationX -= dy * MouseLookCamera.SENSITIVITY;
                this._rotationX = cc.clampf(this._rotationX, -80, 80);
                this.updateCamera();
            }
        }, this);
    }

    private updateCamera(): void {
        cc.log('Camera rotation:', this._rotationX, this._rotationY);
        // Apply rotation to camera node
    }

    onExit(): void {
        cc.eventManager.removeListener(this._listener);
        super.onExit();
    }
}
```

`getDeltaX()` and `getDeltaY()` return the pixel distance the mouse moved since the last frame. Multiply by a sensitivity factor to control rotation speed.

