```typescript
function moveToward(
    current: cc.Point,
    target: cc.Point,
    speed: number,
    dt: number
): cc.Point {
    const diff = cc.pSub(target, current);
    const dist = cc.pLength(diff);

    if (dist <= speed * dt) {
        return cc.p(target.x, target.y);
    }

    const dir = cc.pNormalize(diff);
    return cc.pAdd(current, cc.pMult(dir, speed * dt));
}

// Usage in update:
class Chaser extends cc.Node {
    private _speed: number = 200;
    private _target: cc.Point = cc.p(400, 300);

    update(dt: number): void {
        const current = this.getPosition();
        const newPos = moveToward(current, this._target, this._speed, dt);
        this.setPosition(newPos);

        // Rotate to face movement direction
        const dir = cc.pSub(this._target, current);
        if (cc.pLength(dir) > 1) {
            const angle = Math.atan2(dir.y, dir.x) * cc.DEG;
            this.setRotation(-angle);
        }
    }
}
```

```typescript
class PathEditor extends cc.Layer {
    private _draw: cc.DrawNode;
    private _points: cc.Point[] = [];
    private static readonly DOT_RADIUS = 6;
    private static readonly MIN_POINTS = 2;

    onEnter(): void {
        super.onEnter();
        this._draw = new cc.DrawNode();
        this.addChild(this._draw);

        cc.eventManager.addListener({
            event: cc.EventListener.TOUCH_ONE_BY_ONE,
            onTouchBegan: (touch: cc.Touch): boolean => {
                this.addWaypoint(touch.getLocation());
                return true;
            }
        }, this);
    }

    private addWaypoint(pos: cc.Point): void {
        this._points.push(pos);
        this.redraw();
    }

    clearPath(): void {
        this._points = [];
        this._draw.clear();
    }

    getPoints(): cc.Point[] {
        return this._points.slice();
    }

    private redraw(): void {
        this._draw.clear();
        const pts = this._points;

        // Draw waypoint dots
        for (let i = 0; i < pts.length; i++) {
            const isFirst = i === 0;
            const color = isFirst
                ? cc.color(0, 255, 0, 255)
                : cc.color(255, 255, 0, 255);
            this._draw.drawDot(
                pts[i], PathEditor.DOT_RADIUS, color
            );
        }

        // Draw straight-line connections
        for (let i = 0; i < pts.length - 1; i++) {
            this._draw.drawSegment(
                pts[i], pts[i + 1], 0.5,
                cc.color(100, 100, 100, 150)
            );
        }

        // Draw smooth Catmull-Rom spline
        if (pts.length >= PathEditor.MIN_POINTS) {
            this._draw.drawCatmullRom(
                pts, 50, 2,
                cc.color(0, 200, 255, 255)
            );
        }
    }
}

// Usage:
const editor = new PathEditor();
this.addChild(editor);
// Touch screen to add waypoints; path updates in real-time.
```

```typescript
class EquippedCharacter extends cc.Node {
    private _armature: ccs.Armature;
    private _equipment: Map<string, cc.Sprite> = new Map();

    constructor(armatureName: string, exportJson: string) {
        super();
        ccs.armatureDataManager.addArmatureFileInfo(exportJson);
        this._armature = ccs.Armature.create(armatureName);
        this.addChild(this._armature);
        this._armature.animation.play('idle', -1, -1);
        this.scheduleUpdate();
    }

    equip(slotBone: string, spriteName: string): void {
        this.unequip(slotBone);
        const bone = this._armature.getBone(slotBone);
        if (!bone) return;

        const itemSprite = new cc.Sprite(
            cc.spriteFrameCache.getSpriteFrame(spriteName)
        );
        this.addChild(itemSprite, 10);
        this._equipment.set(slotBone, itemSprite);
    }

    unequip(slotBone: string): void {
        const existing = this._equipment.get(slotBone);
        if (existing) {
            existing.removeFromParent(true);
            this._equipment.delete(slotBone);
        }
    }

    update(dt: number): void {
        // Update equipment positions to follow bones
        this._equipment.forEach((sprite, boneName) => {
            const bone = this._armature.getBone(boneName);
            if (!bone) return;
            const worldPos = bone.getWorldPosition();
            sprite.setPosition(worldPos);
        });
    }

    playAnimation(name: string, loop: boolean): void {
        const loopVal = loop ? -1 : 0;
        this._armature.animation.play(name, 5, loopVal);
    }
}

