output:
```typescript
class Minimap {
    private container: cc.LayerColor;
    private dots: cc.LayerColor[] = [];
    private mapScale: number;
    private mapWidth: number;
    private mapHeight: number;

    private static readonly DOT_SIZE = 4;
    private static readonly BG_ALPHA = 180;

    constructor(width: number, height: number, worldWidth: number) {
        this.mapWidth = width;
        this.mapHeight = height;
        this.mapScale = width / worldWidth;

        this.container = new cc.LayerColor(
            cc.color(0, 0, 0, Minimap.BG_ALPHA),
            width, height
        );
    }

    getNode(): cc.LayerColor {
        return this.container;
    }

    addEntity(worldX: number, worldY: number, color: cc.Color): number {
        const dot = new cc.LayerColor(
            color,
            Minimap.DOT_SIZE, Minimap.DOT_SIZE
        );
        const mapX = worldX * this.mapScale;
        const mapY = worldY * this.mapScale;
        dot.setPosition(
            Math.min(mapX, this.mapWidth - Minimap.DOT_SIZE),
            Math.min(mapY, this.mapHeight - Minimap.DOT_SIZE)
        );
        this.container.addChild(dot, 1);
        this.dots.push(dot);
        return this.dots.length - 1;
    }

    updateEntity(index: number, worldX: number, worldY: number): void {
        if (index < 0 || index >= this.dots.length) return;
        const mapX = Math.min(worldX * this.mapScale, this.mapWidth - Minimap.DOT_SIZE);
        const mapY = Math.min(worldY * this.mapScale, this.mapHeight - Minimap.DOT_SIZE);
        this.dots[index].setPosition(mapX, mapY);
    }
}

// Usage:
const winSize = cc.director.getWinSize();
const minimap = new Minimap(120, 90, 2400);
const node = minimap.getNode();
node.setPosition(winSize.width - 130, winSize.height - 100);
this.addChild(node, 50);

const playerDot = minimap.addEntity(100, 200, cc.color(0, 255, 0, 255));
const enemyDot = minimap.addEntity(500, 300, cc.color(255, 0, 0, 255));
minimap.updateEntity(playerDot, 150, 220);
```

The minimap background is a semi-transparent `cc.LayerColor`. Each entity is a small colored `cc.LayerColor` dot positioned by scaling world coordinates. `addEntity` returns an index for `updateEntity` to move dots as entities move in the world.

