Use a sine wave in the update function:

```typescript
class BobbingNode extends cc.Sprite {
    private baseY: number = 0;
    private elapsed: number = 0;
    private amplitude: number = 20;
    private frequency: number = 2;

    onEnter(): void {
        super.onEnter();
        this.baseY = this.y;
        this.scheduleUpdate();
    }

    update(dt: number): void {
        this.elapsed += dt;
        this.y = this.baseY + Math.sin(this.elapsed * this.frequency * Math.PI * 2) * this.amplitude;
    }

    onExit(): void {
        this.unscheduleUpdate();
        super.onExit();
    }
}
```

Build a level manager that loads resources before transitioning:

```typescript
class LevelManager {
    private static _currentLevel: number = 0;

    static loadLevel(levelNum: number): void {
        const levelPath = 'res/levels/level' + levelNum + '.json';
        const assets = [
            levelPath,
            'res/levels/level' + levelNum + '_bg.png'
        ];

        // Show loading scene
        const loading = new LoadingScene();
        cc.director.runScene(loading);

        cc.loader.load(assets, (err) => {
            if (err) {
                cc.error('Failed to load level', levelNum);
                return;
            }

            const levelData = cc.loader.getRes(levelPath);
            LevelManager._currentLevel = levelNum;

            const gameScene = new GameScene();
            gameScene.setLevelData(levelData);
            cc.director.runScene(new cc.TransitionFade(0.5, gameScene));
        });
    }

    static nextLevel(): void {
        // Release current level resources
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '.json');
        cc.loader.release('res/levels/level' + LevelManager._currentLevel + '_bg.png');

        LevelManager.loadLevel(LevelManager._currentLevel + 1);
    }

    static restartLevel(): void {
        LevelManager.loadLevel(LevelManager._currentLevel);
    }

    static get currentLevel(): number {
        return LevelManager._currentLevel;
    }
}

// Usage:
LevelManager.loadLevel(1);
// After beating level:
LevelManager.nextLevel();
```

