node.setVisible(true);
const vis = node.isVisible();
node.visible = false; // direct property

// Opacity (0 = transparent, 255 = opaque)
node.setOpacity(128);    // 50% transparent
const op = node.getOpacity();
node.opacity = 200;      // direct property

// Cascade opacity to children
