This checks whether a Cocos2d-x native object has been destroyed or is still valid:

```typescript
const sprite = new cc.Sprite('res/hero.png');
parentNode.addChild(sprite);

// Later, after potential removal:
if (cc.sys.isObjectValid(sprite)) {
    sprite.setPosition(100, 200);
} else {
    cc.warn('Sprite has been destroyed');
}

// Common use case: deferred callbacks
function delayedAction(node: cc.Node): void {
    setTimeout(() => {
        if (!cc.sys.isObjectValid(node)) {
            cc.warn('Node was destroyed before callback executed');
            return;
        }
        node.setVisible(true);
    }, 2000);
}

